// // This comment suggests that the counter decrements on every positive clock edge when the enable signal is low.
module counter(CLK, RST, EN, Q);
input CLK, RST, EN;
output [3:0] Q;
reg [3:0] Q;

always@(posedge CLK or posedge RST) begin
	if (RST)
		Q <= 0;
	else if (EN)
		Q <= Q + 1;
	else
		Q <= Q;
end

endmodule
